      function setRoleElementVisible(element, visible) {
        if (!element) return;
        element.classList.toggle("is-role-hidden", !visible);
        element.setAttribute("aria-hidden", visible ? "false" : "true");
      }

      function isSidebarNavActionVisible(element) {
        return Boolean(element)
          && !element.classList.contains("is-role-hidden")
          && !element.hidden
          && element.getAttribute("aria-hidden") !== "true";
      }

      function syncSidebarSections() {
        document.querySelectorAll("[data-sidebar-section]").forEach((section) => {
          const actions = [...section.querySelectorAll(".primary-tab, .sidebar-link, .sidebar-footer")];
          const visible = actions.some(isSidebarNavActionVisible);
          setRoleElementVisible(section, visible);
        });
        syncActiveSidebarSection(activeView);
      }

      function sidebarGroupForView(view = activeView) {
        const normalizedView = view === "personProfile"
          ? personProfileParentView()
          : view === "organizationProfile"
            ? organizationProfileParentView()
            : view;
        if (["map", "contacts", "organizations", "activities", "analytics", "quality", "onboarding"].includes(normalizedView)) return "care";
        if (["patients", "experts", "stakeholders"].includes(normalizedView)) return "stakeholders";
        if (["framework", "hospitations", "questionnaire"].includes(normalizedView)) return "planning";
        if (normalizedView === "formats") return "formats";
        return "";
      }

      function setSidebarSectionExpanded(section, expanded) {
        if (!section) return;
        section.classList.toggle("is-expanded", expanded);
        section.classList.toggle("is-collapsed", !expanded);
        const toggle = section.querySelector("[data-sidebar-section-toggle]");
        if (toggle) toggle.setAttribute("aria-expanded", String(expanded));
      }

      function expandSidebarGroup(group) {
        const section = sidebarCollapsibleSections.find((item) => item.dataset.sidebarGroup === group);
        if (!section || !isSidebarNavActionVisible(section)) return false;
        sidebarCollapsibleSections.forEach((item) => {
          if (item !== section) setSidebarSectionExpanded(item, false);
        });
        setSidebarSectionExpanded(section, true);
        return true;
      }

      function toggleSidebarGroupExpansion(group = "") {
        const section = sidebarCollapsibleSections.find((item) => item.dataset.sidebarGroup === group);
        if (!section || !isSidebarNavActionVisible(section)) return false;
        const expanded = !section.classList.contains("is-expanded");
        if (expanded) {
          sidebarCollapsibleSections.forEach((item) => {
            if (item !== section) setSidebarSectionExpanded(item, false);
          });
        }
        setSidebarSectionExpanded(section, expanded);
        return true;
      }

      function toggleSidebarGroup(group = "") {
        return toggleSidebarGroupExpansion(group);
      }

      function syncActiveSidebarSection(view = activeView) {
        const activeGroup = sidebarGroupForView(view);
        sidebarCollapsibleSections.forEach((section) => {
          const active = Boolean(activeGroup) && section.dataset.sidebarGroup === activeGroup;
          section.classList.toggle("is-active-section", active);
          if (active) setSidebarSectionExpanded(section, true);
          else setSidebarSectionExpanded(section, false);
        });
        window.requestAnimationFrame(() => {
          const activeItem = document.querySelector(".sidebar-nav .primary-tab.is-active");
          if (activeItem?.getClientRects().length) activeItem.scrollIntoView({ block: "nearest", inline: "nearest" });
        });
      }

