      function convertMappedImportToManualRows() {
        importState.manualRows = buildImportRows().map((row) => ({
          name: row.name,
          organization: row.organization,
          category: normalizeCategory(row.category),
          specialty: row.specialty,
          postalCode: row.postalCode,
          city: row.city,
          state: row.state,
          email: row.email,
          phone: row.phone,
          linkedin: row.linkedin,
          priority: row.priority || "Mittel",
          owner: row.owner || "",
          themes: row.themes,
          note: row.note,
          source: row.source || importState.parsed?.fileName || "Online-Batch"
        }));
        if (!importState.manualRows.length) importState.manualRows = createManualImportRows(8);
        importState.parsed = {
          fileName: importState.parsed?.fileName || importState.batchId,
          fileSize: importState.parsed?.fileSize || 0,
          fileType: "manual",
          delimiter: "",
          sheets: [],
          sheetData: {},
          selectedSheet: "",
          columns: [],
          rows: importState.manualRows,
          warning: ""
        };
        setImportStep("entry");
      }

