      async function runContactImport({ onlyReady = false } = {}) {
        const rows = buildImportRows();
        const now = new Date().toISOString();
        const importableRows = rows.filter((row) => {
          if (row.skip) return false;
          if (row.errors) return false;
          if (onlyReady && row.status !== "ready") return false;
          return true;
        });
        if (!importableRows.length) {
          window.alert("Es gibt noch keine fehlerfreien Kontakte zum Speichern.");
          if (importState.parsed?.fileType === "manual") renderImportEntry();
          else renderImportReview();
          return;
        }
        const imported = importableRows.map((row, index) =>
          sanitizeContact(
            {
              id: createId(),
              name: row.name,
              organization: row.organization,
              category: normalizeCategory(row.category),
              specialty: row.specialty,
              priority: row.priority || "Mittel",
              email: row.email,
              phone: row.phone,
              linkedin: row.linkedin,
              location: row.location || deriveLocationLabel({ postalCode: row.postalCode, city: row.city }),
              postalCode: row.postalCode,
              city: row.city,
              state: row.state,
              note: [row.note, `Import-Batch: ${importState.batchId}`].filter(Boolean).join("\n"),
              themes: row.themes,
              sources: [row.source, `Batch ${importState.batchId}`].filter(Boolean).join(" | "),
              ...ownerPatchForValue(row.owner || ""),
              createdAt: now,
              updatedAt: now
            },
            contacts.length + index
          )
        );
        const created = [];
        try {
          for (const contact of imported) {
            created.push(await window.dataService.createContact(contact, { action: importState.parsed?.fileType === "manual" ? "create" : "import", batchId: importState.batchId }));
          }
          created.forEach((contact) => contactHistoryCache.delete(contact.id));
          contacts = [...created, ...contacts.filter((contact) => !created.some((item) => item.id === contact.id))].map((contact, index) =>
            sanitizeContact(contact, index)
          );
          setStorageStatus(`${created.length} Kontakte über die geschützte API importiert`);
        } catch (error) {
          console.error("Import konnte nicht gespeichert werden.", error);
          window.alert("Der Import konnte nicht über die geschützte API gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.");
          return;
        }
        activeId = created[0]?.id || null;
        currentPage = 1;
        updateView();
        const counts = importCounts(rows);
        importState.report = {
          imported: imported.length,
          skipped: rows.length - imported.length,
          duplicates: rows.filter((row) => row.duplicate).length,
          errors: counts.errors,
          warnings: counts.warnings,
          fileName: importState.parsed?.fileName || "",
          batchId: importState.batchId,
          rows,
          createdIds: created.map((contact) => contact.id),
          createdContacts: created
        };
        importState.profile = {
          mapping: importState.mapping,
          defaults: importState.defaults,
          source: importState.defaults.source,
          owner: importState.defaults.owner,
          sectorMapping: {}
        };
        importState.step = "report";
        renderImportWizard();
      }

