        importFooter.innerHTML = `
          <button class="action-button" type="button" id="import-close-report">Schließen</button>
          <button class="action-button action-button--primary" type="button" id="import-show-contacts">Importierte Kontakte anzeigen</button>
        `;
        document.getElementById("import-close-report").addEventListener("click", closeImportWizard);
        document.getElementById("import-show-contacts").addEventListener("click", showImportedContacts);
        document.getElementById("show-imported").addEventListener("click", showImportedContacts);
        document.getElementById("export-import-errors").addEventListener("click", exportImportErrors);
        document.getElementById("download-import-report").addEventListener("click", downloadImportReport);
        document.getElementById("rollback-import-batch").addEventListener("click", rollbackImportBatch);
