      async function linkExistingContactToOrganization(organization) {
        const query = window.prompt("Kontakt suchen und zuordnen. Bitte einen Teil des Namens eingeben:");
        if (!query) return;
        const normalizedQuery = query.trim().toLowerCase();
        const matches = contacts.filter((contact) => contact.status !== "archived" && String(contact.displayName || contact.name).toLowerCase().includes(normalizedQuery));
        const contact = matches[0];
        if (!contact) {
          window.alert("Kein passender Kontakt gefunden.");
          return;
        }
        try {
          const updated = await window.dataService.updateContact(contact.id, {
            organizationId: organization.id.startsWith("derived-org-") ? "" : organization.id,
            organization: organization.name
          });
          contacts = contacts.map((item, index) => (item.id === contact.id ? sanitizeContact({ ...item, ...updated }, index) : item));
          organizations = mergeOrganizations(organizations, deriveOrganizationsFromContacts(contacts));
          setStorageStatus("Kontakt mit Organisation verknüpft");
          updateView();
          if (isOrganizationProfileActive("care", organization.id)) renderOrganizationProfilePage();
          else openOrganizationProfile("care", organization.id, { returnTo: "organizations", title: organization.name });
        } catch (error) {
          console.error("Kontakt konnte nicht zugeordnet werden.", error);
          window.alert("Die Zuordnung konnte nicht gespeichert werden. Bitte prüfe Migration, Rolle und Verbindung.");
        }
      }

      async function assignOrganizationToContact(contact) {
        const query = window.prompt("Organisation suchen oder neu als Freitext zuordnen:", contact.organization || "");
        if (query === null) return;
        const name = query.trim();
        if (!name) return;
        const existing = organizations.find((organization) => normalizeOrganizationName(organization.name) === normalizeOrganizationName(name));
        try {
          const updated = await window.dataService.updateContact(contact.id, {
            organizationId: existing && !existing.id.startsWith("derived-org-") ? existing.id : "",
            organization: existing?.name || name
          });
          contacts = contacts.map((item, index) => (item.id === contact.id ? sanitizeContact({ ...item, ...updated }, index) : item));
          organizations = mergeOrganizations(organizations, deriveOrganizationsFromContacts(contacts));
          setStorageStatus("Organisation am Kontakt gespeichert");
          updateView();
          refreshContactDetailView(contact.id);
        } catch (error) {
          console.error("Organisation konnte nicht am Kontakt gespeichert werden.", error);
          window.alert("Die Organisation konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.");
        }
      }

      function openOrganizationEditor(organization = null, options = {}) {
        if (!canEditContacts()) {
          showPermissionDenied(viewerCreateDisabledMessage(organization ? "das Bearbeiten von Organisationen" : "das Anlegen neuer Organisationen"));
          return;
        }
        const isExpertEditor = options.scope === "expert";
        const isPatientEditor = options.scope === "patient";
        setOrganizationEditorScope(isExpertEditor ? "expert" : isPatientEditor ? "patient" : "care");
        editingOrganizationId = organization?.id || null;
        organizationEditorCurrentStep = "quick";
        organizationEditorTitle.textContent = isExpertEditor
          ? organization ? "Expertenkreis-Organisation bearbeiten" : "Expertenkreis-Organisation anlegen"
          : isPatientEditor
            ? organization ? "Patientenorganisation bearbeiten" : "Patientenorganisation anlegen"
          : organization ? "Organisation bearbeiten" : "Organisation anlegen";
        organizationEditorSubtitle.textContent = isExpertEditor
          ? "Organisation aus der Interoperabilität getrennt vom Versorgungsdatenbestand erfassen."
          : isPatientEditor
            ? "Patientenorganisation im Patientenbereich erfassen."
          : organization ? "Stammdaten der Organisation aktualisieren." : "Neue Einrichtung, Institution oder Organisation anlegen.";
        const defaultExpertGroup = expertGroups.find((group) => group.status !== "archived")?.name || seedExpertGroups(expertGroups)[0] || "";
        const selectedSector = isExpertEditor
          ? organization?.sector || defaultExpertGroup
          : isPatientEditor
            ? organization?.sector || organization?.indication || defaultPatientIndication()
            : normalizeCategory(organization?.sector || "");
        organizationEditorForm.elements.id.value = organization?.id || "";
        organizationEditorForm.elements.name.value = organization?.name || "";
        organizationEditorForm.elements.sector.innerHTML = buildContextCategorySelectOptions(selectedSector, organizationEditorScope);
        organizationEditorForm.elements.sector.value = selectedSector;
        organizationEditorForm.elements.organizationType.value = organization?.organizationType || "";
        organizationEditorForm.elements.postalCode.value = organization?.postalCode || "";
        organizationEditorForm.elements.city.value = organization?.city || "";
        organizationEditorForm.elements.state.value = organization?.state || "";
        organizationEditorForm.elements.website.value = organization?.website || "";
        organizationEditorForm.elements.phone.value = organization?.phone || "";
        organizationEditorForm.elements.email.value = organization?.email || "";
        organizationEditorForm.elements.source.value = organization?.source || "";
        organizationEditorForm.elements.notes.value = organization?.notes || "";
        organizationEditorPrimarySystems = organizationEditorScope === "care" && Array.isArray(organization?.primarySystems)
          ? organization.primarySystems.map((system) => ({ ...system }))
          : [];
        renderOrganizationPrimarySystemsEditor();
        organizationEditorStatus.textContent = "";
        organizationEditorStatus.className = "editor-status";
        renderOrganizationEditorStep();
        refreshCustomSelects(organizationEditorDrawer);
        organizationEditorDrawer.classList.add("is-open");
        organizationEditorDrawer.setAttribute("aria-hidden", "false");
        syncBodyScrollLock();
        window.setTimeout(() => organizationEditorForm.elements.name.focus(), 0);
      }

      function closeOrganizationEditor() {
        editingOrganizationId = null;
        organizationEditorScope = "care";
        organizationEditorCurrentStep = "quick";
        closeAllCustomSelects();
        organizationEditorDrawer.classList.remove("is-open");
        organizationEditorDrawer.setAttribute("aria-hidden", "true");
        syncBodyScrollLock();
      }

      function openDetail(id, items = filteredContacts(), options = {}) {
        const expertScope = options.scope === "expert";
        const detailMode = options.mode === "page" ? "page" : options.mode === "preview" ? "preview" : "drawer";
        const isProfilePage = detailMode === "page";
        const isPreview = detailMode === "preview";
        const profileReturnTo = options.returnTo
          || (isProfilePage ? activePersonProfile.returnTo : detailProfileReturnTo)
          || (expertScope ? "experts" : "contacts");
        if (!isProfilePage) detailProfileReturnTo = profileReturnTo;
        const targetPanel = isProfilePage ? personProfileDetailPanel() : detailPanel;
        const rerenderDetail = () => openDetail(contact.id, currentItems, {
          scope: expertScope ? "expert" : "care",
          mode: detailMode,
          returnTo: profileReturnTo
        });
        const sourceContacts = expertScope ? expertContacts : contacts;
        const fallbackItems = expertScope ? filteredExpertContacts() : filteredContacts();
        const currentItems = items.length ? items : fallbackItems;
        const contact = currentItems.find((item) => item.id === id) || sourceContacts.find((item) => item.id === id);
        if (!contact) return;
        const detailContactChanged = expertScope ? activeExpertId !== contact.id : activeId !== contact.id;
        if (detailContactChanged) {
          detailActiveTab = isProfilePage && activePersonProfile.id === contact.id && activePersonProfile.tab
            ? activePersonProfile.tab
            : "overview";
          detailOwnerPickerOpen = false;
          detailImageEditorOpen = false;
          contactEditingNoteId = null;
        }

        const locationText = formatLocationDisplay(contact);
        const linkedinUrl = meaningfulOrEmpty(contact.linkedin);
        const ownerLabel = meaningfulOrEmpty(contact.owner);
        const specialtyText = specialtyLabel(contact);
        const roleText = meaningfulOrEmpty(contact.contactRole);
        const honorificTitle = meaningfulOrEmpty(contact.honorificTitle);
        const noteText = displayNoteText(contact);
        const sourceText = sourceLabel(contact) === "-" ? "" : sourceLabel(contact);
        const websiteText = meaningfulOrEmpty(contact.url) || (sourceText && isValidOptionalUrl(sourceText) ? sourceText : "");
        const websiteHref = isValidOptionalUrl(websiteText) ? websiteText : "";
        const organizationLabel = meaningfulOrEmpty(contact.organization);
        const organizationPool = expertScope ? expertOrganizations : organizations;
        const linkedOrganization = organizationPool.find((organization) =>
          (contact.organizationId && organization.id === contact.organizationId) ||
          (organizationLabel && normalizeOrganizationName(organization.name) === normalizeOrganizationName(organizationLabel))
        );
        const themeTags = normalizeThemes(contact.themes);
        const noteCount = expertScope
          ? parseContactNotesThread(contact.note, contact).length
          : normalizedContactNotes(contact).length;
        const historyCount = contactHistoryCache.get(contact.id)?.length || 0;
        const consentStatus = normalizeMitmachenConsentStatus(contact.mitmachenConsentStatus);
        const linkedCareContacts = expertScope ? linkedContactsForExpertContact(contact) : [];
        const editingDetail = detailEditMode && canEditContacts();
        const editableDetail = canEditContacts();
        const admin = !expertScope && canAdministerData();
        const portraitMarkup = contactAvatarMarkup(contact, "lg");
        const ownerDisplay = ownerDisplayLabel(contact.owner || contact.ownerId);
        const normalizedStatus = String(contact.status || "").trim().toLowerCase();
        const activeTab = normalizeDetailTab(
          detailActiveTab || "overview",
          expertScope ? ["overview", "contact", "themes", "links", "notes", "activity"] : ["overview", "contact", "themes", "consent", "notes", "activity"]
        );
        detailActiveTab = activeTab;
        const editingOverview = editingDetail && activeTab === "overview";
        const editingContactways = editingDetail && activeTab === "contact";
        const statusLabel = normalizedStatus === "archived"
          ? "Archiviert"
          : normalizedStatus && !["active", "aktiv"].includes(normalizedStatus)
            ? contact.status
            : "";
        const profileStatusMarkup = expertScope
          ? ""
          : statusLabel
            ? `<span class="badge badge--status">${escapeHtml(statusLabel)}</span>`
            : "";

        if (expertScope) {
          activeExpertId = contact.id;
          activeExpertOrganizationId = null;
          activeId = null;
          activeOrganizationId = null;
          if (!isProfilePage) renderExpertContactsTable(currentItems);
        } else {
          activeId = contact.id;
          activeExpertId = null;
          activeExpertOrganizationId = null;
          if (!isProfilePage) renderTable(currentItems);
        }
        targetPanel.classList.remove("detail-panel--organization");
        targetPanel.classList.remove("detail-panel--registration");

        const currentIndex = currentItems.findIndex((item) => item.id === contact.id);
        const panelAttrs = (tab) => detailPanelAttrs(tab, activeTab, { ariaTab: true });

        targetPanel.innerHTML = `
          <div class="detail-toolbar">
            ${isProfilePage ? personProfileBackButtonMarkup() : `<div class="detail-counter">${currentIndex + 1} von ${currentItems.length} Kontakten</div>`}
            <div class="detail-toolbar-actions">
              ${isPreview ? `<button class="action-button action-button--primary" type="button" id="detail-open-profile">Profil öffnen</button>` : ""}
              ${
                editingDetail
                  ? `
                    <button class="action-button" type="button" id="detail-cancel-edit">Abbrechen</button>
                    <button class="action-button action-button--primary detail-profile-edit" type="button" id="detail-save-edit">Änderungen speichern</button>
                  `
                  : ""
              }
              ${isProfilePage ? "" : `<button class="detail-close" type="button" id="detail-close" aria-label="Details schlie&szlig;en">&times;</button>`}
            </div>
          </div>
          <div class="detail-content ${isPreview ? "detail-preview" : ""}">
            <div class="detail-profile">
              <section class="detail-profile-top">
                <div class="detail-profile-main">
                  <div class="contact-profile-image">
                    ${portraitMarkup}
                    ${editableDetail && !expertScope ? `<button class="action-button contact-profile-image__edit" type="button" id="detail-image-edit" aria-label="Kontaktbild ändern" title="Kontaktbild ändern">✎</button>` : ""}
                  </div>
                  <div class="detail-profile-copy">
                    ${
                      editingOverview
                        ? `<input class="detail-edit-input detail-edit-input--title" data-detail-field="name" value="${escapeHtml(contact.name)}" aria-label="Name" />`
                      : `<h3>${escapeHtml(contact.displayName)}</h3>`
                    }
                    ${honorificTitle ? `<div class="detail-profile-subline">${escapeHtml(honorificTitle)}</div>` : ""}
                    <div class="detail-profile-role">${escapeHtml(organizationLabel || "Organisation nicht dokumentiert")}</div>
                    ${roleText && !expertScope ? `<div class="detail-profile-subline">${escapeHtml(roleText)}</div>` : ""}
                    ${profileStatusMarkup ? `<div class="detail-profile-status">${profileStatusMarkup}</div>` : ""}
                  </div>
                </div>
                <div class="detail-profile-meta profile-owner-meta detail-contact-owner-meta">${detailHeaderOwnerControl(contact)}</div>
              </section>

              ${detailImageEditorOpen && editableDetail && !expertScope ? `<form id="detail-image-form">${contactImageEditorMarkup(contact)}</form>` : ""}

              <div class="detail-tabs" role="tablist" aria-label="Detailbereiche">
                ${detailTabButton("overview", "Überblick", activeTab, { ariaTab: true, locked: editingDetail })}
                ${detailTabButton("contact", "Kontakt", activeTab, { ariaTab: true, locked: editingDetail })}
                ${detailTabButton("themes", "Themen", activeTab, { ariaTab: true, count: themeTags.length, locked: editingDetail })}
                ${expertScope ? detailTabButton("links", "Verbindungen", activeTab, { ariaTab: true, count: linkedCareContacts.length, locked: editingDetail }) : ""}
                ${expertScope ? "" : detailTabButton("consent", "Einwilligung", activeTab, { ariaTab: true, status: consentStatus, statusLabel: mitmachenConsentStatusLabel(consentStatus), locked: editingDetail })}
                ${detailTabButton("notes", "Notizen", activeTab, { ariaTab: true, count: noteCount, locked: editingDetail })}
                ${detailTabButton("activity", "Aktivitäten", activeTab, { ariaTab: true, count: historyCount, locked: editingDetail })}
              </div>

              <section ${panelAttrs("overview")} id="detail-overview">
                ${sectionTitleMarkup("Stammdaten", "overview", editingDetail)}
                <div class="detail-line-list">
                  ${
                    editingOverview
                      ? renderDetailEditGrid(contact, locationText, { scope: expertScope ? "expert" : "care" })
                      : `
                        ${detailLineHtml(
                          "Organisation",
                          linkedOrganization
                            ? `<button class="organization-contact-link" type="button" ${expertScope ? "data-open-linked-expert-organization" : "data-open-linked-organization"}="${escapeHtml(linkedOrganization.id)}">${escapeHtml(linkedOrganization.name)}</button>`
                            : escapeHtml(organizationLabel || "Keine Organisation hinterlegt") + (editableDetail ? ` <button class="detail-inline-action" type="button" id="detail-assign-organization">Organisation zuordnen</button>` : ""),
                          { empty: !organizationLabel && !linkedOrganization }
                        )}
                        ${detailLine(expertScope ? "Gruppe" : "Sektor", contact.category)}
                        ${detailLine(expertScope ? "Fachbereich / Fokus" : "Fachrichtung", specialtyText, { emptyLabel: expertScope ? "Nicht hinterlegt" : "Bitte wählen" })}
                        ${detailLine("Rolle", roleText)}
                        ${expertScope ? "" : detailLineHtml("Priorität", detailHeaderPriorityControl(contact), { empty: !contact.priority })}
                      `
                  }
                </div>
                ${editingDetail ? "" : `
                  <details class="detail-more">
                    <summary>Weitere Angaben</summary>
                    <div class="detail-more__content">
                      <div class="detail-line-list">
                        ${expertScope || !linkedOrganization?.primarySystems?.length ? "" : detailLine("Primärsysteme der Organisation", linkedOrganization.primarySystems.map(primarySystemDisplayLabel).join("; "))}
                        ${detailLine("Ort", locationText)}
                        ${detailLine("Bundesland", contact.state || stateLabel(contact))}
                        ${honorificTitle ? detailLine("Titel", honorificTitle) : ""}
                        ${expertScope ? detailLine("Quelle", sourceText, { emptyLabel: "Nicht hinterlegt" }) : ""}
                        ${expertScope ? detailLine("Versorgung", `${linkedCareContacts.length} ${linkedCareContacts.length === 1 ? "Verknüpfung" : "Verknüpfungen"}`) : ""}
                        ${detailLine("Aktualisiert", formatDateLabel(contact.updatedAt || contact.createdAt))}
                      </div>
                      <article class="detail-info-card detail-info-card--map detail-info-card--span-full">
                        ${buildDetailMiniMap(contact, locationText)}
                      </article>
                    </div>
                  </details>
                `}
                ${editingDetail || expertScope ? "" : contactExpertContextMarkup(contact)}
                ${editingDetail || expertScope ? "" : renderHospitationProfileSection(hospitationsForContact(contact.id), { kind: "contact", id: contact.id, scope: "care" })}
                ${editingDetail || expertScope ? "" : renderFormatProfileSection(contact)}
              </section>

              <section ${panelAttrs("contact")} id="detail-contactways">
                ${sectionTitleMarkup("Kontakt", "contactways", editingDetail)}
                <div class="detail-line-list">
                  ${
                    editingContactways
                      ? renderContactwaysEditGrid(contact)
                      : `
                        ${detailContactLine("E-Mail", meaningfulOrEmpty(contact.email), `mailto:${meaningfulOrEmpty(contact.email)}`)}
                        ${detailContactLine("Telefon", meaningfulOrEmpty(contact.phone), `tel:${meaningfulOrEmpty(contact.phone)}`)}
                        ${detailContactLine("LinkedIn", linkedinUrl ? "Profil öffnen" : "", linkedinUrl)}
                        ${detailContactLine("Website", websiteText, websiteHref)}
                      `
                  }
                </div>
              </section>

              <section ${panelAttrs("themes")} id="detail-themes">
                <h4 class="detail-section-title">Themen${themeTags.length ? ` (${themeTags.length})` : ""}</h4>
                <div class="detail-line-list">
                  ${editableDetail
                    ? renderDetailThemeEditor(themeTags, { scope: expertScope ? "expert" : "care" })
                    : renderViewerThemePanel(themeTags, { scope: expertScope ? "expert" : "care" })}
                </div>
              </section>

              ${
                expertScope
                  ? `
                    <section ${panelAttrs("links")} id="detail-links">
                      ${
                        expertContactContextMarkup(contact) ||
                        `<div class="expert-context-section">
                          <h4 class="detail-section-title">Auch in Versorgungskontakten</h4>
                          <div class="empty">Noch keine Verknüpfung zu Versorgungskontakten vorhanden.</div>
                        </div>`
                      }
                    </section>
                  `
                  : ""
              }

              ${
                expertScope
                  ? ""
                  : `
                    <section ${panelAttrs("consent")} id="detail-consent">
                      ${renderMitmachenConsentPanel(contact, editableDetail)}
                    </section>
                  `
              }

              <section ${panelAttrs("notes")} id="detail-notes">
                <h4 class="detail-section-title">Notizen</h4>
                ${renderContactNotesThread(contact, { scope: expertScope ? "expert" : "care" })}
              </section>

              <section ${panelAttrs("activity")} id="detail-activity">
                ${
                  expertScope
                    ? `<div class="history-empty">Noch kein Verlauf für diesen Expertenkreis-Kontakt vorhanden.</div>`
                    : `
                      <div class="detail-info-card history-card">
                        <div class="history-head">
                          <div>
                            <h4>Verlauf</h4>
                            <p>Änderungen und Importereignisse.</p>
                          </div>
                        </div>
                        <div class="history-filters" id="history-filters">${renderHistoryFilters(contact.id, [])}</div>
                        <div class="history-timeline" id="history-timeline">
                          <div class="history-loading">Verlauf wird geladen...</div>
                        </div>
                      </div>
                    `
                }
              </section>

              ${
                expertScope
                  ? ""
                  : `
                    <div class="detail-bottom-actions">
                      ${
                        admin && contact.status === "archived"
                          ? `<button class="action-button action-button--primary" type="button" id="detail-restore">Kontakt wiederherstellen</button>`
                          : admin
                            ? `
                              <details class="detail-overflow-actions">
                                <summary class="action-button">Weitere Aktionen</summary>
                                <div class="detail-overflow-actions__menu">
                                  <button class="action-button action-button--danger" type="button" id="detail-delete">Kontakt archivieren</button>
                                </div>
                              </details>
                            `
                            : ""
                      }
                    </div>
                  `
              }
            </div>
          </div>
        `;

        if (!isProfilePage) {
          detailDrawer.classList.add("is-open");
          detailDrawer.setAttribute("aria-hidden", "false");
          syncBodyScrollLock();
        }
        refreshCustomSelects(targetPanel);
        if (!expertScope) loadContactHistory(contact.id);

        targetPanel.querySelector("#detail-close")?.addEventListener("click", closeDetail);
        if (isProfilePage) bindPersonProfileBack(targetPanel);
        if (!expertScope) bindHospitationProfileActions(targetPanel, { kind: "contact", id: contact.id });
        if (!expertScope) bindFormatProfileActions(targetPanel, contact, rerenderDetail);
        targetPanel.querySelector("#detail-open-profile")?.addEventListener("click", () => {
          openPersonProfile(expertScope ? "expert" : "contact", contact.id, { returnTo: profileReturnTo });
        });
        targetPanel.querySelectorAll("[data-detail-edit-section]").forEach((button) => {
          button.addEventListener("click", () => {
            detailEditMode = true;
            detailOwnerPickerOpen = false;
            detailActiveTab = button.dataset.detailEditSection === "contactways" ? "contact" : button.dataset.detailEditSection || detailActiveTab;
            const focusTarget = button.dataset.detailEditFocus || "";
            rerenderDetail();
            window.setTimeout(() => {
              targetPanel.querySelector(`#detail-${button.dataset.detailEditSection}`)?.scrollIntoView({ block: "start" });
              if (focusTarget === "owner") targetPanel.querySelector("[data-detail-owner-picker] input")?.focus();
            }, 0);
          });
        });
        targetPanel.querySelector("#detail-cancel-edit")?.addEventListener("click", () => {
          detailEditMode = false;
          rerenderDetail();
        });
        targetPanel.querySelector("#detail-save-edit")?.addEventListener("click", () => saveDetailInline(contact));
        const detailOwnerPicker = targetPanel.querySelector(".detail-contact-owner-meta [data-detail-owner-picker]");
        const detailOwnerEditButton = targetPanel.querySelector("[data-detail-owner-edit]");
        bindOwnerMultiPickerSearch(detailOwnerPicker);
        const detailOwnerStatus = detailOwnerPicker?.querySelector("[data-owner-picker-status]");
        const detailOwnerSave = detailOwnerPicker?.querySelector("[data-owner-picker-save]");
        const detailOwnerCancel = detailOwnerPicker?.querySelector("[data-owner-picker-cancel]");
        const closeDetailOwnerPicker = ({ restore = false } = {}) => {
          if (restore && detailOwnerPicker) {
            const original = new Set(normalizeOwnerIds(String(detailOwnerPicker.dataset.originalOwnerIds || "").split(",")));
            detailOwnerPicker.querySelectorAll('input[type="checkbox"]').forEach((input) => { input.checked = original.has(input.value); });
          }
          detailOwnerPickerOpen = false;
          if (detailOwnerPicker) detailOwnerPicker.hidden = true;
          detailOwnerEditButton?.setAttribute("aria-expanded", "false");
          detailOwnerEditButton?.focus({ preventScroll: true });
        };
        detailOwnerEditButton?.addEventListener("click", () => {
          detailOwnerPickerOpen = !detailOwnerPickerOpen;
          if (detailOwnerPicker) detailOwnerPicker.hidden = !detailOwnerPickerOpen;
          detailOwnerEditButton.setAttribute("aria-expanded", detailOwnerPickerOpen ? "true" : "false");
          if (detailOwnerPickerOpen) {
            window.requestAnimationFrame(() => detailOwnerPicker?.querySelector("[data-owner-search]")?.focus());
          }
        });
        targetPanel.querySelectorAll("[data-detail-header-field]").forEach((select) => {
          select.addEventListener("change", async () => {
            const field = select.dataset.detailHeaderField;
            await updateContactField(contact.id, field, select.value);
          });
        });
        targetPanel.querySelectorAll("[data-detail-owner-picker]").forEach((picker) => {
          bindOwnerMultiPickerSearch(picker);
          picker.querySelectorAll('input[type="checkbox"]').forEach((input) => {
            input.addEventListener("change", async () => {
              const detailOwnerInput = picker.closest(".detail-edit-owner")?.querySelector("[data-detail-field='owner']");
              if (detailOwnerInput) {
                setOwnerInputValue(detailOwnerInput, selectedOwnerIdsFromPicker(picker));
                return;
              }
              if (detailOwnerStatus) {
                detailOwnerStatus.textContent = "Ungespeicherte Auswahl";
                detailOwnerStatus.classList.remove("is-error");
              }
            });
          });
        });
        detailOwnerCancel?.addEventListener("click", () => closeDetailOwnerPicker({ restore: true }));
        detailOwnerSave?.addEventListener("click", async () => {
          detailOwnerSave.disabled = true;
          if (detailOwnerCancel) detailOwnerCancel.disabled = true;
          if (detailOwnerStatus) {
            detailOwnerStatus.textContent = "Owner werden gespeichert …";
            detailOwnerStatus.classList.remove("is-error");
          }
          detailOwnerPickerOpen = false;
          const saved = await updateContactField(contact.id, "owner", selectedOwnerIdsFromPicker(detailOwnerPicker), {
            scope: expertScope ? "expert" : "care",
            mode: detailMode,
            onError: () => {}
          });
          detailOwnerSave.disabled = false;
          if (detailOwnerCancel) detailOwnerCancel.disabled = false;
          if (!saved && detailOwnerStatus) {
            detailOwnerPickerOpen = true;
            detailOwnerStatus.textContent = "Speichern fehlgeschlagen. Bitte prüfe Rolle und Verbindung.";
            detailOwnerStatus.classList.add("is-error");
          }
        });
        detailOwnerPicker?.addEventListener("keydown", (event) => {
          if (event.key !== "Escape") return;
          event.preventDefault();
          closeDetailOwnerPicker({ restore: true });
        });
        const noteInput = targetPanel.querySelector("#detail-note-input");
        const noteStatus = targetPanel.querySelector("#detail-note-status");
        bindMitmachenConsentInlineEditors(contact, targetPanel);
        targetPanel.querySelector("#detail-note-save")?.addEventListener("click", () => saveDetailNote(contact, noteInput, noteStatus));
        targetPanel.querySelectorAll("[data-viewer-theme-blocked]").forEach((element) => {
          element.addEventListener("click", () => showPermissionDenied(viewerCreateDisabledMessage("das Bearbeiten von Themen")));
          element.addEventListener("focus", () => {
            if (element.matches("input")) showPermissionDenied(viewerCreateDisabledMessage("das Bearbeiten von Themen"));
          }, { once: true });
        });
        noteInput?.addEventListener("input", () => {
          if (noteStatus) noteStatus.textContent = "Nicht gespeicherte Änderung";
        });
        noteInput?.addEventListener("blur", () => saveDetailNote(contact, noteInput, noteStatus));
        noteInput?.addEventListener("keydown", (event) => {
          if ((event.metaKey || event.ctrlKey) && event.key === "Enter") {
            event.preventDefault();
            saveDetailNote(contact, noteInput, noteStatus);
            noteInput.blur();
          }
        });
        bindContactNotesThread(contact, targetPanel, { scope: expertScope ? "expert" : "care" });
        targetPanel.querySelectorAll("[data-detail-theme-toggle]").forEach((button) => {
          button.addEventListener("click", () => {
            const tag = button.dataset.detailThemeToggle;
            const current = new Set(normalizeThemes(contact.themes));
            if (current.has(tag)) current.delete(tag);
            else current.add(tag);
            applyDetailThemeChange(contact, [...current], { scope: expertScope ? "expert" : "care" });
          });
        });
        targetPanel.querySelectorAll("[data-detail-theme-remove]").forEach((button) => {
          button.addEventListener("click", () => {
            const tag = button.dataset.detailThemeRemove;
            applyDetailThemeChange(contact, normalizeThemes(contact.themes).filter((item) => item !== tag), { scope: expertScope ? "expert" : "care" });
          });
        });
        const addTheme = () => {
          const input = targetPanel.querySelector("#detail-theme-input");
          const value = String(input?.value || "").trim();
          if (!value) return;
          applyDetailThemeChange(contact, [...normalizeThemes(contact.themes), value], { scope: expertScope ? "expert" : "care" });
        };
        targetPanel.querySelector("#detail-theme-add")?.addEventListener("click", addTheme);
        targetPanel.querySelector("#detail-theme-input")?.addEventListener("keydown", (event) => {
          if (event.key === "Enter") {
            event.preventDefault();
            addTheme();
          }
        });
        targetPanel.querySelector("#detail-image-edit")?.addEventListener("click", () => {
          detailImageEditorOpen = !detailImageEditorOpen;
          rerenderDetail();
        });
        const detailImageForm = targetPanel.querySelector("#detail-image-form");
        if (detailImageForm) {
          let selectedImageFile = null;
          bindContactImageDropzone(detailImageForm, contact, (file) => {
            selectedImageFile = file;
            detailImageForm.elements.imageUrl.value = "";
            setContactImageStatus(detailImageForm, "Bild ist ausgewählt und wird beim Speichern hochgeladen.");
          });
          detailImageForm.elements.imageUrl.addEventListener("input", () => {
            if (!detailImageForm.elements.imageUrl.value.trim()) return;
            selectedImageFile = null;
            detailImageForm.elements.imageFile.value = "";
          });
          const applyDetailImageResult = (updated) => {
            contacts = contacts.map((item, index) => item.id === contact.id ? sanitizeContact({ ...item, ...updated }, index) : item);
            contactHistoryCache.delete(contact.id);
            detailImageEditorOpen = false;
            setStorageStatus("Kontaktbild gespeichert");
            updateView();
            rerenderDetail();
          };
          detailImageForm.addEventListener("submit", async (event) => {
            event.preventDefault();
            const imageUrl = String(detailImageForm.elements.imageUrl.value || "").trim();
            const options = {
              sourceLabel: String(detailImageForm.elements.imageSourceLabel.value || "").trim(),
              rightsNote: String(detailImageForm.elements.imageRightsNote.value || "").trim()
            };
            if (!selectedImageFile && !imageUrl) {
              setContactImageStatus(detailImageForm, "Bitte wähle eine Datei oder gib einen HTTPS-Bildlink ein.", "error");
              return;
            }
            setContactImageStatus(detailImageForm, "Kontaktbild wird gespeichert …");
            try {
              const updated = selectedImageFile
                ? await window.dataService.uploadContactImage(contact.id, selectedImageFile, options)
                : await window.dataService.setContactImageLink(contact.id, await validateRemoteContactImage(imageUrl), options);
              applyDetailImageResult(updated);
            } catch (error) {
              setContactImageStatus(detailImageForm, error.message || "Kontaktbild konnte nicht gespeichert werden.", "error");
            }
          });
          detailImageForm.querySelector("[data-contact-image-remove]")?.addEventListener("click", async () => {
            setContactImageStatus(detailImageForm, "Kontaktbild wird entfernt …");
            try {
              applyDetailImageResult(await window.dataService.removeContactImage(contact.id));
            } catch (error) {
              setContactImageStatus(detailImageForm, error.message || "Kontaktbild konnte nicht entfernt werden.", "error");
            }
          });
          detailImageForm.querySelector("[data-contact-image-cancel]")?.addEventListener("click", () => {
            detailImageEditorOpen = false;
            rerenderDetail();
          });
        }
        targetPanel.querySelector("#detail-delete")?.addEventListener("click", () => deleteContact(contact));
        targetPanel.querySelector("#detail-restore")?.addEventListener("click", () => restoreContact(contact));
        targetPanel.querySelector("[data-open-linked-organization]")?.addEventListener("click", (event) => {
          openOrganizationProfile("care", event.currentTarget.dataset.openLinkedOrganization, { returnTo: "organizations" });
        });
        targetPanel.querySelector("[data-open-linked-expert-organization]")?.addEventListener("click", (event) => {
          activeExpertMode = "organizations";
          openOrganizationProfile("expert", event.currentTarget.dataset.openLinkedExpertOrganization, { returnTo: "experts" });
        });
        bindExpertEntityLinkControls(() => rerenderDetail(), targetPanel);
        targetPanel.querySelector("#detail-assign-organization")?.addEventListener("click", () => assignOrganizationToContact(contact));
        bindDetailTabNavigation(targetPanel, (tab) => {
          detailActiveTab = tab;
          if (isProfilePage) {
            activePersonProfile.tab = tab;
            if (tab !== "notes") {
              activePersonProfile.noteId = "";
              activeContactNoteTargetId = "";
            }
            updateRouteHash(personProfileRoute(activePersonProfile.kind, activePersonProfile.id));
          }
          rerenderDetail();
        });
        if (productTourState.open && currentProductTourSteps()[productTourState.index]?.id === "contact-profile") {
          scheduleProductTourLayout();
        }
      }

      function closeDetail() {
        closeAllCustomSelects();
        detailEditMode = false;
        detailOwnerPickerOpen = false;
        detailImageEditorOpen = false;
        detailActiveTab = "overview";
        detailProfileReturnTo = "";
        organizationDetailActiveTab = "overview";
        contactEditingNoteId = null;
        stakeholderEditingNoteKey = "";
        activeRegistrationId = null;
        activeExpertId = null;
        activeExpertOrganizationId = null;
        activeStakeholderPersonId = null;
        activeStakeholderOrganizationId = null;
        registrationDetailTab = "contact";
        detailPanel.classList.remove("detail-panel--organization");
        detailPanel.classList.remove("detail-panel--registration");
        detailDrawer.classList.remove("is-open");
        detailDrawer.setAttribute("aria-hidden", "true");
        syncBodyScrollLock();
      }

      function openEditor(contact = null, options = {}) {
        if (!canEditContacts()) {
          showPermissionDenied(viewerCreateDisabledMessage(contact ? "das Bearbeiten von Kontakten" : "das Anlegen neuer Kontakte"));
          return;
        }
        const isExpertEditor = options.scope === "expert";
        const isPatientEditor = options.scope === "patient";
        setEditorScope(isExpertEditor ? "expert" : isPatientEditor ? "patient" : "care");
        const organizationDefaults = options.organization || null;
        const derivedPrefix = isExpertEditor ? "expert-derived-org-" : isPatientEditor ? "patient-derived-org-" : "derived-org-";
        pendingEditorOrganizationId = organizationDefaults?.id && !organizationDefaults.id.startsWith(derivedPrefix) ? organizationDefaults.id : "";
        editorMode = contact ? "edit" : "create";
        editingId = contact?.id || null;
        const splitLocation = splitLocationLabel(contact?.location || "");
        editorForm.dataset.submitAction = "save";
        editorTitle.textContent = isExpertEditor
          ? contact ? "Expertenkreis-Kontakt bearbeiten" : "Expertenkreis-Kontakt anlegen"
          : isPatientEditor
            ? contact ? "Patienten-Kontakt bearbeiten" : "Patienten-Kontakt anlegen"
          : contact ? "Kontakt bearbeiten" : "Neuen Kontakt anlegen";
        editorSubtitle.textContent = isExpertEditor
          ? "Interoperabilitätskontakt getrennt vom Versorgungsdatenbestand erfassen."
          : isPatientEditor
            ? "Kontakt im Patientenbereich erfassen. Nur Name ist Pflicht."
          : contact
            ? "Basisdaten zuerst, Details können laufend ergänzt werden."
            : "Nur Name ist Pflicht. Details kannst du später ergänzen.";
        editorHint.textContent = isExpertEditor
          ? "Neue Expertenkreis-Kontakte werden separat gespeichert."
          : isPatientEditor
            ? "Neue Patienten-Kontakte werden im Patientenbereich gespeichert."
          : contact
            ? "Änderungen werden über die geschützte API gespeichert und protokolliert."
            : "Neue Kontakte werden über die geschützte API angelegt.";
        const selectedOrganizationName = contact?.organization || organizationDefaults?.name || "";
        const defaultExpertGroup = expertGroups.find((group) => group.status !== "archived")?.name || seedExpertGroups(expertGroups)[0] || "";
        const selectedCategory = isExpertEditor
          ? contact?.category || defaultExpertGroup
          : isPatientEditor
            ? contact?.category || contact?.indication || organizationDefaults?.sector || defaultPatientIndication()
            : normalizeCategory(contact?.category || organizationDefaults?.sector || "");

        editorForm.elements.id.value = contact?.id || "";
        editorForm.elements.name.value = contact?.name || "";
        editorForm.elements.specialty.value = contact?.specialty || "";
        editorForm.elements.contactRole.value = contact?.contactRole || "";
        editorCurrentStep = "quick";
        editorForm.elements.category.innerHTML = buildContextCategorySelectOptions(selectedCategory, editorScope);
        editorForm.elements.category.value = selectedCategory;
        editorForm.elements.priority.value = contact?.priority || "Mittel";
        editorForm.elements.organization.value = selectedOrganizationName;
        updateOrganizationSuggestions(selectedOrganizationName);
        editorForm.elements.email.value = contact?.email || "";
        editorForm.elements.phone.value = contact?.phone || "";
        editorForm.elements.linkedin.value = contact?.linkedin || "";
        const selectedOwnerIds = contact ? contactOwnerIds(contact) : normalizeOwnerIds(currentProfile?.id || "");
        ensureOwnerProfile(currentProfile);
        renderEditorOwnerPicker(selectedOwnerIds);
        editorForm.elements.postalCode.value = contact?.postalCode || organizationDefaults?.postalCode || splitLocation.postalCode || "";
        editorForm.elements.city.value = contact?.city || organizationDefaults?.city || splitLocation.city || "";
        editorForm.elements.state.value = contact?.state || organizationDefaults?.state || "";
        editorForm.elements.street.value = contact?.street || "";
        const contactNoteIsThread = isContactNotesThread(contact?.note);
        editorForm.elements.note.disabled = contactNoteIsThread;
        editorForm.elements.note.value = contactNoteIsThread ? "" : contact?.note || "";
        editorForm.elements.note.placeholder = contactNoteIsThread
          ? "Notizen werden im Reiter Notizen als Verlauf gepflegt."
          : "Kurze Notiz zum Kontakt...";
        clearEditorImagePreviewUrl();
        editorForm.elements.imageFile.value = "";
        editorForm.elements.imageRemove.value = "";
        editorForm.elements.image.value = isExpertEditor || isPatientEditor
          ? contact?.url || contact?.image || ""
          : contact?.imageKind === "external" || (!contact?.imageKind && !contact?.imageStoragePath && contact?.image)
            ? contact.image
            : "";
        editorForm.elements.imageSourceLabel.value = isExpertEditor ? "" : contact?.imageSourceLabel || "";
        editorForm.elements.imageRightsNote.value = isExpertEditor ? "" : contact?.imageRightsNote || "";
        setContactImagePreview(document.getElementById("editor-contact-image-preview"), contact || sanitizeContact({ name: "Neuer Kontakt" }, contacts.length), contact?.image || "");
        setContactImageStatus(editorForm, "");
        renderEditorSpecialtyOptions(contact?.specialty || "");
        setEditorThemes(contact?.themes || []);
        refreshEditorCustomSelects();
        renderEditorStep();
        updateEditorDuplicateHint();
        [
          "name",
          "organization",
          "category",
          "specialty",
          "postalCode",
          "city",
          "state",
          "location",
          "owner",
          "email",
          "themesText"
        ].forEach((field) => setEditorFieldMessage(field, "", ""));
        editorStatus.textContent = "";
        editorStatus.className = "editor-status";

        editorDrawer.classList.add("is-open");
        editorDrawer.setAttribute("aria-hidden", "false");
        syncBodyScrollLock();
        window.setTimeout(() => editorForm.elements.name.focus(), 0);
      }

      function closeEditor() {
        editorForm.dataset.submitAction = "save";
        clearEditorImagePreviewUrl();
        closeAllCustomSelects();
        editorDrawer.classList.remove("is-open");
        editorDrawer.setAttribute("aria-hidden", "true");
        syncBodyScrollLock();
      }

      async function deleteContact(contact) {
        if (!canAdministerData()) {
          showPermissionDenied("Nur Admins dürfen Kontakte archivieren.");
          return;
        }
        const confirmed = window.confirm(`Soll "${contact.displayName}" archiviert werden? Der Kontakt wird nicht physisch gelöscht und die Archivierung erscheint im Verlauf.`);
        if (!confirmed) return;
        try {
          const archived = await window.dataService.archiveContact(contact.id);
          contacts = contacts.map((item, index) => (item.id === contact.id ? sanitizeContact({ ...item, ...archived }, index) : item));
          contactHistoryCache.delete(contact.id);
          setStorageStatus("Kontakt über die geschützte API archiviert");
        } catch (error) {
          console.error("Kontakt konnte nicht archiviert werden.", error);
          window.alert("Der Kontakt konnte nicht archiviert werden. Nur Admins dürfen archivieren.");
          return;
        }
        activeId = null;
        closeDetail();
        updateView();
      }

      async function restoreContact(contact) {
        if (!canAdministerData()) {
          showPermissionDenied("Nur Admins dürfen archivierte Kontakte wiederherstellen.");
          return;
        }
        const confirmed = window.confirm(`Soll "${contact.displayName}" wieder in den aktiven Datenbestand aufgenommen werden? Die Wiederherstellung erscheint im Verlauf.`);
        if (!confirmed) return;
        try {
          const restored = await window.dataService.restoreContact(contact.id);
          contacts = contacts.map((item, index) => (item.id === contact.id ? sanitizeContact(restored, index) : item));
          contactHistoryCache.delete(contact.id);
          setStorageStatus("Kontakt über die geschützte API wiederhergestellt");
        } catch (error) {
          console.error("Kontakt konnte nicht wiederhergestellt werden.", error);
          window.alert("Der Kontakt konnte nicht wiederhergestellt werden. Bitte prüfe Anmeldung, Rolle und Verbindung.");
          return;
        }
        showingArchive = false;
        activeId = contact.id;
        closeDetail();
        updateView();
        openPersonProfile("contact", contact.id, { returnTo: "contacts" });
      }

      function serializeContactsToCsv(items) {
        const header = [
          "id",
          "name",
          "honorificTitle",
          "specialty",
          "category",
          "organization",
          "topic",
          "themes",
          "priority",
          "email",
          "phone",
          "linkedin",
          "location",
          "city",
          "state",
          "street",
          "postalCode",
          "url",
          "description",
          "lat",
          "lon",
          "note",
          "nextStep",
          "image",
          "sources",
          "lastExchange",
          "owner",
          "createdAt",
          "updatedAt"
        ];

        const rows = items.map((contact) =>
          [
            contact.id,
            contact.name,
            contact.honorificTitle,
            contact.specialty,
            contact.category,
            contact.organization,
            contact.topic,
            normalizeThemes(contact.themes).join(" | "),
            contact.priority,
            contact.email,
            contact.phone,
            contact.linkedin,
            contact.location,
            contact.city,
            contact.state,
            contact.street,
            contact.postalCode,
            contact.url,
            contact.description,
            contact.lat,
            contact.lon,
            contact.note,
            contact.nextStep,
            contact.image,
            normalizeSources(contact.sources).join(" | "),
            contact.lastExchange,
            contactOwnerDisplayNames(contact).join("; "),
            contact.createdAt,
            contact.updatedAt
          ]
            .map(csvEscape)
            .join(",")
        );

        return [header.join(","), ...rows].join("\n");
      }

      function downloadCsv() {
        const csv = serializeContactsToCsv(contacts);
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = "versorgungs-kompass-local-export.csv";
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      }

      function selectedContacts() {
        return contacts.filter((contact) => selectedContactIds.has(contact.id));
      }

      function downloadSelectedCsv() {
        const items = selectedContacts();
        if (!items.length) return;
        const csv = serializeContactsToCsv(items);
        const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.href = url;
        link.download = `versorgungs-kompass-auswahl-${items.length}.csv`;
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
      }

      async function assignOwnerToSelectedContacts() {
        if (!selectedContactIds.size) return;
        if (!canEditContacts()) {
          showPermissionDenied("Du hast Leserechte. Owner können nur von Editor- oder Admin-Nutzern geändert werden.");
          return;
        }
        const normalizedOwner = String(bulkOwnerSelect?.value || "").trim();
        if (!normalizedOwner) {
          window.alert("Bitte zuerst einen Owner auswählen.");
          return;
        }
        const selectedCount = selectedContactIds.size;
        try {
          for (const id of [...selectedContactIds]) {
            const contact = contacts.find((item) => item.id === id);
            await updateContactField(id, "owner", [...contactOwnerIds(contact), normalizedOwner], { silent: true });
          }
          const ownerLabel = ownerDisplayLabel(normalizedOwner) || "Owner";
          setStorageStatus(`${selectedCount} Kontakte aktualisiert: ${ownerLabel} hinzugefügt`);
          selectedContactIds.clear();
          updateView();
        } catch (error) {
          console.error("Owner-Zuweisung konnte nicht abgeschlossen werden.", error);
          window.alert("Die Owner-Zuweisung konnte nicht abgeschlossen werden.");
        }
      }

      async function archiveSelectedContacts() {
        const items = selectedContacts();
        if (!items.length) return;
        if (!canAdministerData()) {
          showPermissionDenied("Nur Admins dürfen Kontakte archivieren.");
          return;
        }
        const confirmed = window.confirm(`${items.length} Kontakte archivieren? Die Kontakte werden nicht physisch gelöscht.`);
        if (!confirmed) return;
        try {
          for (const contact of items) {
            const archived = await window.dataService.archiveContact(contact.id);
            contacts = contacts.map((item, index) => (item.id === contact.id ? sanitizeContact({ ...item, ...archived }, index) : item));
            contactHistoryCache.delete(contact.id);
          }
          selectedContactIds.clear();
          if (items.some((contact) => contact.id === activeId)) {
            activeId = null;
            closeDetail();
          }
          setStorageStatus(`${items.length} Kontakte archiviert`);
          updateView();
        } catch (error) {
          console.error("Kontakte konnten nicht archiviert werden.", error);
          window.alert("Die Kontakte konnten nicht archiviert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.");
        }
      }

