      const frameworkAccordionButtons = Array.from(document.querySelectorAll("[data-framework-accordion-target]"));
      const frameworkAccordions = Array.from(document.querySelectorAll("#view-framework [data-framework-accordion]"))
        .filter((accordion) => accordion instanceof HTMLDetailsElement);
      let frameworkScrollAnimationFrame = 0;

      function cancelFrameworkScroll() {
        if (!frameworkScrollAnimationFrame) return;
        window.cancelAnimationFrame(frameworkScrollAnimationFrame);
        frameworkScrollAnimationFrame = 0;
      }

      function syncFrameworkAccordionButtons() {
        frameworkAccordionButtons.forEach((button) => {
          const accordionId = button.getAttribute("aria-controls");
          const accordion = accordionId ? document.getElementById(accordionId) : null;
          button.setAttribute("aria-expanded", accordion instanceof HTMLDetailsElement && accordion.open ? "true" : "false");
        });
      }

      function scrollToFrameworkAccordion(accordion) {
        const summary = accordion.querySelector(":scope > summary");
        summary?.focus({ preventScroll: true });
        const targetTop = Math.max(0, accordion.getBoundingClientRect().top + window.scrollY - 12);
        if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
          window.scrollTo({ top: targetTop, behavior: "auto" });
          return;
        }
        cancelFrameworkScroll();
        const startTop = window.scrollY;
        const distance = targetTop - startTop;
        const duration = 1100;
        const startedAt = window.performance.now();
        const animateScroll = (now) => {
          const progress = Math.min((now - startedAt) / duration, 1);
          const easedProgress = progress < 0.5
            ? 4 * progress * progress * progress
            : 1 - Math.pow(-2 * progress + 2, 3) / 2;
          window.scrollTo({ top: startTop + distance * easedProgress, behavior: "auto" });
          if (progress < 1) {
            frameworkScrollAnimationFrame = window.requestAnimationFrame(animateScroll);
          } else {
            frameworkScrollAnimationFrame = 0;
          }
        };
        frameworkScrollAnimationFrame = window.requestAnimationFrame(animateScroll);
      }

      frameworkAccordions.forEach((accordion) => {
        accordion.querySelector(":scope > summary")?.addEventListener("click", cancelFrameworkScroll);
        accordion.addEventListener("toggle", () => {
          if (accordion.open) {
            frameworkAccordions.forEach((otherAccordion) => {
              if (otherAccordion !== accordion) otherAccordion.open = false;
            });
          }
          syncFrameworkAccordionButtons();
        });
      });

      frameworkAccordionButtons.forEach((button) => {
        const accordionId = button.getAttribute("aria-controls");
        const accordion = accordionId ? document.getElementById(accordionId) : null;
        if (!(accordion instanceof HTMLDetailsElement)) return;
        button.addEventListener("click", () => {
          frameworkAccordions.forEach((otherAccordion) => {
            if (otherAccordion !== accordion) otherAccordion.open = false;
          });
          accordion.open = true;
          syncFrameworkAccordionButtons();
          window.requestAnimationFrame(() => scrollToFrameworkAccordion(accordion));
        });
      });
      syncFrameworkAccordionButtons();

