      organizationEditorForm?.addEventListener("submit", async (event) => {
        event.preventDefault();
        if (!canEditContacts()) {
          showPermissionDenied("Organisationen können nur von Editor- oder Admin-Nutzern gespeichert werden.");
          return;
        }
        const formData = new FormData(organizationEditorForm);
        const primarySystems = organizationEditorScope === "care" ? readOrganizationPrimarySystemsEditor() : [];
        const payload = {
          name: String(formData.get("name") || "").trim(),
          sector: organizationEditorScope === "expert"
            ? String(formData.get("sector") || "").trim()
            : organizationEditorScope === "patient"
              ? String(formData.get("sector") || "").trim() || defaultPatientIndication()
              : normalizeCategory(formData.get("sector") || ""),
          organizationType: String(formData.get("organizationType") || "").trim(),
          postalCode: String(formData.get("postalCode") || "").trim(),
          city: String(formData.get("city") || "").trim(),
          state: String(formData.get("state") || "").trim(),
          website: String(formData.get("website") || "").trim(),
          phone: String(formData.get("phone") || "").trim(),
          email: String(formData.get("email") || "").trim(),
          source: String(formData.get("source") || "").trim(),
          notes: String(formData.get("notes") || "").trim()
        };
        if (!payload.name) {
          organizationEditorStatus.textContent = "Bitte trage einen Namen ein.";
          organizationEditorStatus.className = "editor-status is-visible editor-status--error";
          organizationEditorForm.elements.name.focus();
          return;
        }
        if (organizationEditorScope === "expert") {
          if (!payload.sector) {
            organizationEditorStatus.textContent = "Bitte wähle eine Gruppe aus.";
            organizationEditorStatus.className = "editor-status is-visible editor-status--error";
            setOrganizationEditorStep("quick");
            organizationEditorForm.elements.sector.focus();
            return;
          }
          const group = expertGroupByName(payload.sector);
          const expertPayload = {
            ...payload,
            group: group?.name || payload.sector,
            groupId: group?.id || "",
            sector: group?.name || payload.sector,
            source: payload.source || "Manuell angelegt"
          };
          try {
            const saved = sanitizeExpertOrganization(await window.dataService.createExpertOrganization(expertPayload), expertOrganizations.length);
            expertOrganizations = mergeExpertOrganizations(
              [saved, ...expertOrganizations.filter((organization) => organization.id !== saved.id)],
              deriveExpertOrganizationsFromContacts(expertContacts)
            );
            setStorageStatus("Expertenkreis-Organisation gespeichert");
            closeOrganizationEditor();
            activeExpertMode = "organizations";
            activeExpertDuplicates = false;
            activeCareDuplicateView = "";
            openOrganizationProfile("expert", saved.id, { returnTo: "experts", title: saved.name });
          } catch (error) {
            console.error("Expertenkreis-Organisation konnte nicht gespeichert werden.", error);
            organizationEditorStatus.textContent = "Expertenkreis-Organisation konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.";
            organizationEditorStatus.className = "editor-status is-visible editor-status--error";
          }
          return;
        }
        if (organizationEditorScope === "patient") {
          const patientOrganizationEntry = sanitizePatientOrganization({
            ...payload,
            id: editingOrganizationId || patientStakeholderId("patient-org", payload.name),
            stakeholderTypeId: "patient-associations",
            stakeholderType: "patient-associations",
            organizationType: payload.organizationType || "Patientenorganisation",
            indication: payload.sector,
            category: payload.sector,
            source: payload.source || "Manuell angelegt",
            status: "active",
            updatedAt: new Date().toISOString()
          }, patientOrganizations.length);
          try {
            await upsertPatientStakeholders({ organizations: [patientOrganizationEntry] });
            const saved = patientOrganizationForIdentity(patientOrganizationEntry.id, patientOrganizationEntry.name, patientOrganizations) || patientOrganizationEntry;
            setStorageStatus("Patientenorganisation gespeichert");
            closeOrganizationEditor();
            activePatientMode = "organizations";
            activePatientOrganizationId = saved.id;
            activePatientPersonId = null;
            activeCareDuplicateView = "";
            setActiveView("patients");
            updateRouteHash("patients");
            updateView();
            openOrganizationProfile("patient", saved.id, { returnTo: "patients", title: saved.name });
          } catch (error) {
            console.error("Patientenorganisation konnte nicht gespeichert werden.", error);
            organizationEditorStatus.textContent = "Patientenorganisation konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.";
            organizationEditorStatus.className = "editor-status is-visible editor-status--error";
          }
          return;
        }
        try {
          const savedOrganization = editingOrganizationId && !editingOrganizationId.startsWith("derived-org-")
            ? await window.dataService.updateOrganization(editingOrganizationId, payload)
            : await window.dataService.createOrganization(payload);
          const savedPrimarySystems = await window.dataService.saveOrganizationPrimarySystems(savedOrganization.id, primarySystems);
          const saved = { ...savedOrganization, primarySystems: savedPrimarySystems };
          organizations = mergeOrganizations([saved, ...organizations.filter((organization) => organization.id !== saved.id)], deriveOrganizationsFromContacts(contacts));
          setStorageStatus("Organisation über die geschützte API gespeichert");
          closeOrganizationEditor();
          openOrganizationProfile("care", saved.id, { returnTo: "organizations", title: saved.name });
        } catch (error) {
          console.error("Organisation konnte nicht gespeichert werden.", error);
          organizationEditorStatus.textContent = "Organisation konnte nicht gespeichert werden. Bitte prüfe Migration, Rolle und Verbindung.";
          organizationEditorStatus.className = "editor-status is-visible editor-status--error";
        }
      });
