      window.addEventListener("message", (event) => {
        if (event.origin !== window.location.origin || !event.data || typeof event.data !== "object" || Array.isArray(event.data)) return;
        const sourceFrame = [mapViewFrame, stakeholderMapFrame].find((frame) => frame?.contentWindow === event.source);
        if (!sourceFrame) return;
        const expectedChannel = sourceFrame === mapViewFrame ? "contacts" : "stakeholders";
        const message = event.data;
        const messageId = typeof message.id === "string" ? message.id.trim() : "";
        if (
          message.type !== "versorgungs-kompass-open-detail" ||
          message.version !== MAP_MESSAGE_VERSION ||
          message.channel !== expectedChannel ||
          !MAP_MESSAGE_CHANNELS.has(message.channel) ||
          message.realm !== expectedChannel ||
          !/^[A-Za-z0-9][A-Za-z0-9._:-]{0,159}$/.test(messageId)
        ) return;
        if (message.realm === "stakeholders") {
            activeStakeholderMode = "organizations";
            currentPage = 1;
            openPersonProfile("stakeholder", messageId, { returnTo: "stakeholders" });
            return;
        }
        openPersonEntry("contact", messageId, mapContacts(), { returnTo: "map" });
      });

