      editorForm.addEventListener("submit", async (event) => {
        event.preventDefault();
        if (!canEditContacts()) {
          showPermissionDenied("Du hast Leserechte. Kontakte können nur von Editor- oder Admin-Nutzern gespeichert werden.");
          return;
        }
        const formData = new FormData(editorForm);
        const timestamp = new Date().toISOString();
        const existingContact = editingId
          ? editorScope === "patient"
            ? patientPeople.find((contact) => contact.id === editingId)
            : contacts.find((contact) => contact.id === editingId)
          : null;
        const validation = validateEditorValues({ showWarnings: true });
        if (validation.errors.length) {
          const firstErrorField = validation.errors[0]?.field;
          focusEditorFieldByName(firstErrorField);
          return;
        }
        const pendingContactImageFile = editorScope === "care" && formData.get("imageFile") instanceof File && formData.get("imageFile").size
          ? formData.get("imageFile")
          : null;
        const pendingContactImageUrl = editorScope === "care" ? String(formData.get("image") || "").trim() : "";
        const pendingContactImageRemoval = editorScope === "care" && formData.get("imageRemove") === "true";
        if (pendingContactImageFile) {
          if (!["image/jpeg", "image/png", "image/webp"].includes(pendingContactImageFile.type)) {
            setEditorStep("sources");
            setContactImageStatus(editorContactImageRoot, "Bitte nutze ein JPG-, PNG- oder WebP-Bild.", "error");
            return;
          }
          if (pendingContactImageFile.size > 5 * 1024 * 1024) {
            setEditorStep("sources");
            setContactImageStatus(editorContactImageRoot, "Das Kontaktbild darf maximal 5 MB groß sein.", "error");
            return;
          }
        }
        const existingExternalImage = existingContact && !existingContact.imageStoragePath ? existingContact.image || "" : "";
        if (pendingContactImageUrl && pendingContactImageUrl !== existingExternalImage && !pendingContactImageFile) {
          try {
            await validateRemoteContactImage(pendingContactImageUrl);
          } catch (error) {
            setEditorStep("sources");
            setContactImageStatus(editorContactImageRoot, error.message, "error");
            editorForm.elements.image.focus();
            return;
          }
        }
        const postalCode = String(formData.get("postalCode") || "").trim();
        const city = String(formData.get("city") || "").trim();
        const derivedLocation = deriveLocationLabel({ postalCode, city });
        const locationValue = derivedLocation || existingContact?.location || "";
        const organizationName = editorOrganizationValue();
        let selectedOrganization = selectedEditorOrganization();
        if (organizationName && !selectedOrganization) {
          const result = await createEditorOrganizationByName(organizationName);
          selectedOrganization = result?.organization || null;
        }
        const organizationDerivedPrefix = editorScope === "expert"
          ? "expert-derived-org-"
          : editorScope === "patient"
            ? "patient-derived-org-"
            : "derived-org-";
        const organizationId = selectedOrganization?.id && !selectedOrganization.id.startsWith(organizationDerivedPrefix)
          ? selectedOrganization.id
          : pendingEditorOrganizationId || existingContact?.organizationId || "";
        if (editorScope === "expert") {
          const group = expertGroupByName(String(formData.get("category") || "").trim());
          if (!group?.id) {
            editorStatus.textContent = "Bitte wähle eine Gruppe aus.";
            editorStatus.className = "editor-status is-visible editor-status--error";
            setEditorStep("quick");
            focusEditorFieldByName("category");
            return;
          }
          const expertEntry = {
            id: String(formData.get("id") || "").trim() || undefined,
            name: String(formData.get("name") || "").trim(),
            specialty: String(formData.get("specialty") || "").trim(),
            contactRole: String(formData.get("contactRole") || "").trim(),
            group: group.name,
            groupId: group.id,
            category: group.name,
            organization: organizationName,
            organizationId: selectedOrganization?.id && !selectedOrganization.id.startsWith("expert-derived-org-")
              ? selectedOrganization.id
              : pendingEditorOrganizationId || "",
            email: String(formData.get("email") || "").trim(),
            phone: String(formData.get("phone") || "").trim(),
            linkedin: String(formData.get("linkedin") || "").trim(),
            city,
            state: String(formData.get("state") || "").trim(),
            note: String(formData.get("note") || "").trim(),
            themes: editorThemes,
            ...ownerPatchForValue(formData.get("owner")),
            sources: ["Manuell angelegt"],
            source: "Manuell angelegt",
            url: String(formData.get("image") || "").trim(),
            status: "active",
            createdAt: timestamp,
            updatedAt: timestamp
          };
          try {
            const savedExpertContact = sanitizeExpertContact(await window.dataService.createExpertContact(expertEntry), expertContacts.length);
            expertContacts = [savedExpertContact, ...expertContacts.filter((contact) => contact.id !== savedExpertContact.id)];
            expertOrganizations = mergeExpertOrganizations(expertOrganizations, deriveExpertOrganizationsFromContacts(expertContacts));
            setStorageStatus("Expertenkreis-Kontakt gespeichert");
            activeExpertId = savedExpertContact.id;
            activeExpertMode = "contacts";
            activeExpertDuplicates = false;
            activeCareDuplicateView = "";
            editorForm.dataset.submitAction = "save";
            closeEditor();
            setActiveView("experts");
            updateRouteHash("experts");
            updateView();
            openPersonProfile("expert", savedExpertContact.id, { returnTo: "experts" });
          } catch (error) {
            console.error("Expertenkreis-Kontakt konnte nicht gespeichert werden.", error);
            editorStatus.textContent = "Expertenkreis-Kontakt konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.";
            editorStatus.className = "editor-status is-visible editor-status--error";
          }
          return;
        }
        if (editorScope === "patient") {
          const indication = String(formData.get("category") || "").trim() || selectedOrganization?.sector || defaultPatientIndication();
          const name = String(formData.get("name") || "").trim();
          const role = String(formData.get("contactRole") || "").trim() || String(formData.get("specialty") || "").trim();
          const focus = String(formData.get("specialty") || "").trim();
          const patientEntry = sanitizePatientPerson({
            id: String(formData.get("id") || "").trim() || patientStakeholderId("patient-person", organizationName || "ohne-organisation", name),
            stakeholderTypeId: "patient-associations",
            stakeholderType: "patient-associations",
            organization: organizationName,
            organizationId,
            name,
            role,
            contactRole: role,
            committee: focus,
            city,
            state: String(formData.get("state") || "").trim(),
            email: String(formData.get("email") || "").trim(),
            phone: String(formData.get("phone") || "").trim(),
            linkedin: String(formData.get("linkedin") || "").trim(),
            note: String(formData.get("note") || "").trim() || existingContact?.note || "",
            themes: normalizeThemes([...editorThemes, focus].filter(Boolean)),
            url: String(formData.get("image") || "").trim(),
            source: "Manuell angelegt",
            indication,
            sector: indication,
            category: indication,
            createdAt: existingContact?.createdAt || timestamp,
            updatedAt: timestamp,
            status: "active"
          }, patientPeople.length, patientOrganizations);

          if (!patientEntry.name) {
            window.alert("Bitte trage mindestens einen Namen ein.");
            editorForm.elements.name.focus();
            return;
          }

          try {
            await upsertPatientStakeholders({ people: [patientEntry] });
            const savedPatient = patientPeople.find((person) => person.id === patientEntry.id) || patientEntry;
            setStorageStatus("Patienten-Kontakt gespeichert");
            activePatientMode = "people";
            activePatientPersonId = savedPatient.id;
            activePatientOrganizationId = null;
            editorForm.dataset.submitAction = "save";
            closeEditor();
            setActiveView("patients");
            updateRouteHash("patients");
            updateView();
            openPersonProfile("stakeholder", savedPatient.id, { returnTo: "patients", title: savedPatient.name });
          } catch (error) {
            console.error("Patienten-Kontakt konnte nicht gespeichert werden.", error);
            editorStatus.textContent = "Patienten-Kontakt konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.";
            editorStatus.className = "editor-status is-visible editor-status--error";
          }
          return;
        }
        const entry = {
          id: formData.get("id") || createId(),
          name: String(formData.get("name") || "").trim(),
          specialty: String(formData.get("specialty") || "").trim(),
          contactRole: String(formData.get("contactRole") || "").trim(),
          category: normalizeCategory(formData.get("category") || ""),
          organization: organizationName,
          organizationId,
          topic: existingContact?.topic || "",
          priority: String(formData.get("priority") || "Mittel"),
          email: String(formData.get("email") || "").trim(),
          phone: String(formData.get("phone") || "").trim(),
          linkedin: String(formData.get("linkedin") || "").trim(),
          mitmachenConsentStatus: existingContact?.mitmachenConsentStatus || "not_requested",
          mitmachenConsentEffectiveAt: existingContact?.mitmachenConsentEffectiveAt || "",
          mitmachenConsentSource: existingContact?.mitmachenConsentSource || "",
          mitmachenConsentTextVersion: existingContact?.mitmachenConsentTextVersion || "",
          mitmachenConsentRecordedBy: existingContact?.mitmachenConsentRecordedBy || "",
          mitmachenConsentNote: existingContact?.mitmachenConsentNote || "",
          location: locationValue,
          city,
          state: String(formData.get("state") || "").trim(),
          street: String(formData.get("street") || "").trim(),
          postalCode,
          note: String(formData.get("note") || "").trim() || existingContact?.note || "",
          nextStep: existingContact?.nextStep || "",
          image: existingContact?.imageStoragePath ? "" : existingExternalImage,
          imageSourceUrl: existingContact?.imageSourceUrl || "",
          imageSourceLabel: String(formData.get("imageSourceLabel") || "").trim(),
          imageRightsNote: String(formData.get("imageRightsNote") || "").trim(),
          imageUpdatedAt: existingContact?.imageUpdatedAt || "",
          imageUpdatedBy: existingContact?.imageUpdatedBy || "",
          imageStoragePath: existingContact?.imageStoragePath || "",
          imageKind: existingContact?.imageKind || (existingExternalImage ? "external" : ""),
          imageMimeType: existingContact?.imageMimeType || "",
          imageFileSize: existingContact?.imageFileSize || 0,
          imageWidth: existingContact?.imageWidth || 0,
          imageHeight: existingContact?.imageHeight || 0,
          sources: existingContact?.sources || [],
          themes: editorThemes,
          lastExchange: existingContact?.lastExchange || "",
          ...ownerPatchForValue(formData.get("owner")),
          createdAt: existingContact?.createdAt || timestamp,
          updatedAt: timestamp
        };

        if (!entry.name) {
          window.alert("Bitte trage mindestens einen Namen ein.");
          editorForm.elements.name.focus();
          return;
        }

        const sanitized = sanitizeContact(entry, contacts.length);

        let savedContact;
        try {
          if (editorMode === "edit" && editingId) {
            savedContact = await window.dataService.updateContact(editingId, sanitized);
            contacts = contacts.map((contact, index) =>
              contact.id === editingId ? sanitizeContact({ ...contact, ...savedContact, id: editingId }, index) : contact
            );
            contactHistoryCache.delete(editingId);
          } else {
            savedContact = await window.dataService.createContact(sanitized);
            contacts = [sanitizeContact(savedContact, contacts.length), ...contacts];
            contactHistoryCache.delete(savedContact.id);
          }
          setStorageStatus("Kontakt über die geschützte API gespeichert");
        } catch (error) {
          console.error("Kontakt konnte nicht gespeichert werden.", error);
          editorStatus.textContent = "Kontakt konnte nicht gespeichert werden. Bitte prüfe Anmeldung, Rolle und Verbindung.";
          editorStatus.className = "editor-status is-visible editor-status--error";
          return;
        }

        try {
          let imageUpdatedContact = null;
          if (pendingContactImageFile) {
            imageUpdatedContact = await window.dataService.uploadContactImage(savedContact.id, pendingContactImageFile, {
              sourceLabel: String(formData.get("imageSourceLabel") || "").trim(),
              rightsNote: String(formData.get("imageRightsNote") || "").trim()
            });
          } else if (pendingContactImageRemoval) {
            imageUpdatedContact = await window.dataService.removeContactImage(savedContact.id);
          } else if (pendingContactImageUrl && pendingContactImageUrl !== existingExternalImage) {
            imageUpdatedContact = await window.dataService.setContactImageLink(savedContact.id, pendingContactImageUrl, {
              sourceLabel: String(formData.get("imageSourceLabel") || "").trim(),
              rightsNote: String(formData.get("imageRightsNote") || "").trim()
            });
          }
          if (imageUpdatedContact) {
            savedContact = imageUpdatedContact;
            contacts = contacts.map((contact, index) =>
              contact.id === savedContact.id ? sanitizeContact({ ...contact, ...savedContact }, index) : contact
            );
            contactHistoryCache.delete(savedContact.id);
          }
        } catch (error) {
          console.error("Kontaktbild konnte nicht gespeichert werden.", error);
          editorMode = "edit";
          editingId = savedContact.id;
          editorForm.elements.id.value = savedContact.id;
          setEditorStep("sources");
          setContactImageStatus(editorContactImageRoot, `Der Kontakt wurde gespeichert, das Bild jedoch nicht: ${error.message}`, "error");
          setStorageStatus("Kontakt gespeichert · Kontaktbild ausstehend");
          updateView();
          return;
        }

        activeId = savedContact.id;
        editorForm.dataset.submitAction = "save";
        closeEditor();
        updateView();
        openPersonProfile("contact", savedContact.id, { returnTo: "contacts" });
      });

      document.addEventListener("keydown", (event) => {
        if (event.key === "Escape") {
          if (productTourState.open) {
            closeProductTour({ skipped: true });
            return;
          }
          const hasOpenCustomSelect = [...document.querySelectorAll("[data-custom-select] select")].some((select) =>
            select.closest("[data-custom-select]")?.classList.contains("is-open")
          );
          if (hasOpenCustomSelect) {
            closeAllCustomSelects();
            return;
          }
          if (organizationCombobox?.classList.contains("is-open")) {
            setOrganizationComboboxOpen(false);
            return;
          }
          if (notificationPopover && !notificationPopover.hidden) {
            closeNotificationPopover();
            return;
          }
          if (isMobileLayout() && appShell?.classList.contains("is-mobile-sidebar-expanded")) {
            closeMobileSidebar();
            window.setTimeout(() => sidebarCollapseButton?.focus({ preventScroll: true }), 0);
            return;
          }
          closeMenus();
          if (importDrawer.classList.contains("is-open")) {
            closeImportWizard();
          } else if (formatParticipantDrawer?.classList.contains("is-open")) {
            closeParticipantPlanner();
          } else if (organizationEditorDrawer.classList.contains("is-open")) {
            closeOrganizationEditor();
          } else if (editorDrawer.classList.contains("is-open")) {
            closeEditor();
          } else {
            closeDetail();
          }
        }
      });

      document.addEventListener("click", (event) => {
        const clickTarget = event.target instanceof Element ? event.target : null;
        if (isMobileLayout() && appShell?.classList.contains("is-mobile-sidebar-expanded") && !clickTarget?.closest(".app-sidebar")) {
          closeMobileSidebar();
        }
        if (!clickTarget?.closest("#notification-popover") && !clickTarget?.closest("#sidebar-notifications-button")) closeNotificationPopover();
        if (!clickTarget?.closest("#contact-content-search-results") && !clickTarget?.closest(".search-shell") && contactContentSearchResultsNode) {
          contactContentSearchResultsNode.hidden = true;
        }
        if (!clickTarget?.closest(".menu-shell") && !clickTarget?.closest(".filter-shell") && !clickTarget?.closest(".topbar-account") && !clickTarget?.closest(".column-menu-shell")) closeMenus();
        const clickedInsideCustomSelect = (event.composedPath?.() || []).some((node) =>
          node instanceof Element && (node.matches?.("[data-custom-select]") || Boolean(node.closest?.("[data-custom-select]")))
        ) || Boolean(clickTarget?.closest("[data-custom-select]"));
        if (!clickedInsideCustomSelect) closeAllCustomSelects();
        if (!clickTarget?.closest("[data-organization-combobox]")) setOrganizationComboboxOpen(false);
      });

      window.addEventListener("resize", () => {
        if (filterPanel.hidden) document.body.classList.remove("mobile-filter-open");
        else document.body.classList.toggle("mobile-filter-open", isMobileLayout());
        if (filterPanel.hidden) document.documentElement.classList.remove("mobile-filter-open");
        else document.documentElement.classList.toggle("mobile-filter-open", isMobileLayout());
        syncBodyScrollLock();
        const nextViewportWidth = window.innerWidth;
        const nextMobileLayout = isMobileLayout();
        const viewportModeChanged = nextMobileLayout !== lastViewportMobileLayout;
        const layoutChanged = viewportModeChanged || Math.abs(nextViewportWidth - lastViewportWidth) > 1;
        lastViewportWidth = nextViewportWidth;
        lastViewportMobileLayout = nextMobileLayout;
        if (viewportModeChanged && nextMobileLayout) {
          appShell?.classList.remove("is-sidebar-collapsed");
          setMobileSidebarExpanded(false);
        }
        else if (viewportModeChanged) {
          appShell?.classList.remove("is-mobile-sidebar-expanded");
          restoreSidebarState();
        }
        if (layoutChanged) updateView();
        if (productTourState.open) {
          const steps = currentProductTourSteps();
          positionProductTourPanel(productTourState.target, steps[productTourState.index] || null);
        }
        positionNotificationPopover();
      });

      function routeViewFromHash() {
        const hashView = String(window.location.hash || "").replace(/^#/, "");
        if (!hashView && isHospitationDocumentationStandalone) {
          activeHospitationTab = "appointments";
          return "hospitations";
        }
        const hospitationRoute = parseHospitationRoute(hashView);
        if (hospitationRoute) {
          activeHospitationTab = hospitationRoute.tab;
          return "hospitations";
        }
        if (hashView === "planning") {
          return "framework";
        }
        const personRoute = parsePersonProfileRoute(hashView);
        if (personRoute) {
          detailActiveTab = personRoute.tab || "overview";
          contactEditingNoteId = null;
          stakeholderEditingNoteKey = "";
          activeContactNoteTargetId = personRoute.noteId || "";
          activePersonProfile = {
            kind: personRoute.kind,
            id: personRoute.id,
            returnTo: personProfileParentView(personRoute.kind),
            title: viewLabels.personProfile.title,
            tab: personRoute.tab || "",
            noteId: personRoute.noteId || ""
          };
          return "personProfile";
        }
        const organizationRoute = parseOrganizationProfileRoute(hashView);
        if (organizationRoute) {
          organizationDetailActiveTab = "overview";
          activeOrganizationProfile = {
            kind: organizationRoute.kind,
            id: organizationRoute.id,
            returnTo: organizationProfileParentView(organizationRoute.kind),
            title: viewLabels.organizationProfile.title
          };
          return "organizationProfile";
        }
        const profileImportsRoute = /^profile-imports(?::(registrations|imports|onlineEntry|importHistory))?$/.exec(hashView);
        if (profileImportsRoute) {
          setSettingsTab(profileImportsRoute[1] || "registrations");
          setProfileTab("imports");
          return "profile";
        }
        if (hashView === "notifications" || hashView === "profile-notifications") {
          setProfileTab("notifications");
          return "profile";
        }
        if (hashView === "settings" || hashView === "profile-settings") {
          setProfileTab("settings");
          return "profile";
        }
        if (hashView === "about" || hashView === "profile-about") {
          setProfileTab("about");
          return "profile";
        }
        if (hashView === "changelog" || hashView === "profile-changelog") {
          setProfileTab("changelog");
          return "profile";
        }
        if (hashView === "profile") {
          setProfileTab("profile");
          return "profile";
        }
        if (hashView === "onboarding" && onboardingActive) {
          return "onboarding";
        }
        if (settingsTabItems.some((item) => item.id === hashView)) {
          setSettingsTab(hashView);
          setProfileTab("imports");
          return "profile";
        }
        return viewLabels[hashView] ? hashView : "";
      }

      window.addEventListener("hashchange", () => {
        const nextView = routeViewFromHash() || "home";
        if (onboardingActive && nextView !== "onboarding") {
          updateRouteHash("onboarding");
          return;
        }
        if (nextView === "hospitations" && activeHospitationTab !== "observations") closeHospitationObservationDrawer();
        setActiveView(nextView);
        updateView();
      });

      async function loadExpertData({ includeArchived = false } = {}) {
        expertDataState = "loading";
        try {
          const service = window.dataService;
          if (!service?.loadExpertGroups || !service?.loadExpertContacts || !service?.loadExpertOrganizations) {
            throw new Error("Der geschützte Expertenkreis-Datendienst ist nicht verfügbar.");
          }

          const [loadedGroups, loadedContacts, loadedOrganizations, loadedLinks] = await Promise.all([
            service.loadExpertGroups({ includeArchived }),
            service.loadExpertContacts({ includeArchived }),
            service.loadExpertOrganizations({ includeArchived }),
            service.loadExpertEntityLinks ? service.loadExpertEntityLinks() : Promise.resolve([])
          ]);
          expertGroups = (Array.isArray(loadedGroups) ? loadedGroups : []).map((group, index) =>
            normalizeExpertGroupEntry(group, index)
          );
          expertContacts = (Array.isArray(loadedContacts) ? loadedContacts : []).map((contact, index) =>
            sanitizeExpertContact(contact, index)
          );
          const protectedOrganizations = (Array.isArray(loadedOrganizations) ? loadedOrganizations : []).map((organization, index) =>
            sanitizeExpertOrganization(organization, index)
          );
          expertOrganizations = mergeExpertOrganizations(protectedOrganizations, deriveExpertOrganizationsFromContacts(expertContacts));
          expertEntityLinks = Array.isArray(loadedLinks) ? loadedLinks : [];
          expertDataState = "ready";
        } catch (error) {
          console.error("Expertenkreis-Daten konnten nicht aus dem geschützten Backend geladen werden; ein statischer Fallback ist absichtlich deaktiviert.", error);
          expertGroups = [];
          expertContacts = [];
          expertOrganizations = [];
          expertEntityLinks = [];
          expertDataState = "error";
          throw error;
        }
      }

      async function loadStakeholderData({ includeArchived = false } = {}) {
        let requestedTypeId = activeStakeholderTypeId;
        try {
          const service = window.dataService;
          if (!service?.loadStakeholderTypes || !service?.loadStakeholderOrganizations || !service?.loadStakeholderPeople) {
            throw new Error("Der geschützte Stakeholder-Datendienst ist nicht verfügbar.");
          }

          const loadedTypes = await service.loadStakeholderTypes({ includeArchived });
          stakeholderTypes = (Array.isArray(loadedTypes) ? loadedTypes : []).map((type, index) =>
            sanitizeStakeholderType(type, index)
          );
          normalizeActiveStakeholderType();
          requestedTypeId = activeStakeholderTypeId;

          const [loadedOrganizations, loadedPeople] = await Promise.all([
            service.loadStakeholderOrganizations({ includeArchived, stakeholderTypeId: requestedTypeId }),
            service.loadStakeholderPeople({ includeArchived, stakeholderTypeId: requestedTypeId })
          ]);
          const protectedOrganizations = (Array.isArray(loadedOrganizations) ? loadedOrganizations : []).map((organization, index) =>
            sanitizeStakeholderOrganization(organization, index)
          );
          const protectedPeople = (Array.isArray(loadedPeople) ? loadedPeople : []).map((person, index) =>
            sanitizeStakeholderPerson(person, index)
          );
          stakeholderOrganizations = [
            ...stakeholderOrganizations.filter((organization) => organization.stakeholderTypeId !== requestedTypeId),
            ...protectedOrganizations
          ].sort((left, right) => left.name.localeCompare(right.name, "de"));
          stakeholderPeople = [
            ...stakeholderPeople.filter((person) => person.stakeholderTypeId !== requestedTypeId),
            ...protectedPeople
          ].sort((left, right) => left.name.localeCompare(right.name, "de"));
          loadedStakeholderPeopleTypeIds.add(requestedTypeId);
        } catch (error) {
          console.error("Stakeholder-Daten konnten nicht aus dem geschützten Backend geladen werden; ein statischer Fallback ist absichtlich deaktiviert.", error);
          if (requestedTypeId) {
            stakeholderOrganizations = stakeholderOrganizations.filter((organization) => organization.stakeholderTypeId !== requestedTypeId);
            stakeholderPeople = stakeholderPeople.filter((person) => person.stakeholderTypeId !== requestedTypeId);
            loadedStakeholderPeopleTypeIds.delete(requestedTypeId);
          } else {
            stakeholderTypes = [];
            stakeholderOrganizations = [];
            stakeholderPeople = [];
            loadedStakeholderPeopleTypeIds.clear();
          }
          throw error;
        }
      }

      async function loadPatientData({ includeArchived = false } = {}) {
        try {
          const service = window.dataService;
          if (!service?.loadStakeholderOrganizations || !service?.loadStakeholderPeople) {
            throw new Error("Der geschützte Patientendatendienst ist nicht verfügbar.");
          }

          const [loadedOrganizations, loadedPeople] = await Promise.all([
            service.loadStakeholderOrganizations({ includeArchived, stakeholderTypeId: "patient-associations" }),
            service.loadStakeholderPeople({ includeArchived, stakeholderTypeId: "patient-associations" })
          ]);
          const protectedOrganizations = (Array.isArray(loadedOrganizations) ? loadedOrganizations : []).filter(isPatientAssociationEntry);
          const protectedPeople = (Array.isArray(loadedPeople) ? loadedPeople : []).filter(isPatientAssociationEntry);
          const indicationNames = [...new Set([
            ...protectedOrganizations.map((organization) => organization.indication || organization.sector || organization.category),
            ...protectedPeople.map((person) => person.indication || person.sector || person.category)
          ].map((value) => String(value || "").trim()).filter(Boolean))].sort((left, right) => left.localeCompare(right, "de"));
          patientIndications = indicationNames.map((name, index) => normalizePatientIndicationEntry({
            id: `patient-indication-${normalizeClassPart(name)}`,
            name,
            sortOrder: (index + 1) * 10
          }, index));
          patientOrganizations = protectedOrganizations.map((organization, index) =>
            sanitizePatientOrganization(organization, index)
          );
          patientPeople = protectedPeople.map((person, index) =>
            sanitizePatientPerson(person, index, patientOrganizations)
          );
          syncPatientStakeholderCaches();
        } catch (error) {
          console.error("Patienten- und Verbandsdaten konnten nicht aus dem geschützten Backend geladen werden; ein statischer Fallback ist absichtlich deaktiviert.", error);
          patientIndications = [];
          patientOrganizations = [];
          patientPeople = [];
          stakeholderOrganizations = stakeholderOrganizations.filter((organization) => !isPatientAssociationEntry(organization));
          stakeholderPeople = stakeholderPeople.filter((person) => !isPatientAssociationEntry(person));
          loadedStakeholderPeopleTypeIds.delete("patient-associations");
          throw error;
        }
      }

      async function loadOrganizationData({ includeArchived = false } = {}) {
        try {
          if (window.dataService.loadOrganizations) {
            organizations = mergeOrganizations(await window.dataService.loadOrganizations({ includeArchived }), deriveOrganizationsFromContacts(contacts));
          } else {
            organizations = deriveOrganizationsFromContacts(contacts);
          }
        } catch (organizationError) {
          console.warn("Organisationen konnten nicht aus dem Backend geladen werden. Kontaktbasierter Fallback aktiv.", organizationError);
          organizations = deriveOrganizationsFromContacts(contacts);
        }
      }

      async function loadFormatData({ includeArchived = false } = {}) {
        formatDataState = "loading";
        try {
          formats = window.dataService.loadFormats ? await window.dataService.loadFormats({ includeArchived }) : [];
          formatLoadErrorMessage = "";
          formatDataState = "ready";
          activeFormatId = formats.find((format) => format.status !== "Archiviert")?.id || formats[0]?.id || null;
        } catch (formatError) {
          console.warn("Formate konnten nicht geladen werden.", formatError);
          formatLoadErrorMessage = String(formatError?.message || "Bitte prüfe die geschützte API und Rollenberechtigung für Formate.");
          formats = [];
          formatDataState = "error";
        }
      }

      async function loadHospitationData({ includeArchived = false } = {}) {
        hospitationDataState = "loading";
        try {
          const [loadedSlots, loadedHospitations, loadedRoadmapItems, loadedRoadmapAssessments, loadedUnmetNeeds] = await Promise.all([
            window.dataService.loadHospitationSlots ? window.dataService.loadHospitationSlots({ includeArchived }) : [],
            window.dataService.loadHospitations ? window.dataService.loadHospitations({ includeArchived }) : [],
            window.dataService.loadRoadmapItems ? window.dataService.loadRoadmapItems() : [],
            window.dataService.loadHospitationRoadmapAssessments ? window.dataService.loadHospitationRoadmapAssessments({ includeArchived }) : [],
            window.dataService.loadHospitationUnmetNeeds ? window.dataService.loadHospitationUnmetNeeds({ includeArchived }) : []
          ]);
          hospitationSlots = Array.isArray(loadedSlots) ? loadedSlots : [];
          hospitations = Array.isArray(loadedHospitations) ? loadedHospitations : [];
          roadmapItems = Array.isArray(loadedRoadmapItems) ? loadedRoadmapItems : [];
          hospitationRoadmapAssessments = Array.isArray(loadedRoadmapAssessments) ? loadedRoadmapAssessments : [];
          hospitationUnmetNeeds = Array.isArray(loadedUnmetNeeds) ? loadedUnmetNeeds : [];
          if (window.dataService.loadHospitationObservations) {
            hospitationObservations = await window.dataService.loadHospitationObservations({ includeArchived });
          } else {
            hospitationObservations = hospitationDashboardAllObservations(hospitations).filter((item) => !item.synthetic);
          }
          mergeCanonicalObservationsIntoHospitations();
          hospitationLoadErrorMessage = "";
          hospitationDataState = "ready";
        } catch (hospitationError) {
          console.warn("Hospitationen konnten nicht geladen werden.", hospitationError);
          hospitationLoadErrorMessage = String(hospitationError?.message || "Bitte prüfe die geschützte API und Rollenberechtigung für Hospitationen.");
          hospitationSlots = [];
          hospitations = [];
          roadmapItems = [];
          hospitationRoadmapAssessments = [];
          hospitationUnmetNeeds = [];
          hospitationObservations = [];
          hospitationDataState = "error";
        }
      }

      async function loadCriticalInitialData() {
        const settingsPromise = loadUserSettings();
        const [profiles, profile] = await Promise.all([
          window.dataService.getProfiles(),
          window.dataService.getCurrentProfile()
        ]);
        applyProfiles(profiles);
        renderAccountProfile(profile);
        await settingsPromise;
        contacts = (await window.dataService.loadContacts({ includeArchived: canAdministerData() })).map((contact, index) => sanitizeContact(contact, index));
        organizations = deriveOrganizationsFromContacts(contacts);
        loadedContactsFromStorage = false;
        setStorageStatus(String(window.VERSORGUNGS_COMPASS_CONFIG?.dataMode || "").toLowerCase() === "demo"
          ? `${contacts.length} synthetische Demo-Kontakte lokal geladen`
          : `${contacts.length} Kontakte aus dem Backend geladen`);
      }

      let deferredInitialDataPromise = null;

      function scheduleDeferredInitialData() {
        if (deferredInitialDataPromise) return deferredInitialDataPromise;
        const includeArchived = canAdministerData();
        const run = () => {
          deferredInitialDataPromise = loadDeferredInitialData({ includeArchived });
          return deferredInitialDataPromise;
        };
        if ("requestIdleCallback" in window) {
          window.requestIdleCallback(run, { timeout: 500 });
        } else {
          window.setTimeout(run, 0);
        }
        return deferredInitialDataPromise;
      }

      async function loadDeferredInitialData({ includeArchived = false } = {}) {
        const refreshAfter = async (task) => {
          await task;
          updateView();
        };
        await Promise.allSettled([
          refreshAfter(loadOrganizationData({ includeArchived })),
          refreshAfter(loadFormatData({ includeArchived })),
          refreshAfter(loadHospitationData({ includeArchived })),
          refreshAfter(loadExpertData({ includeArchived })),
          refreshAfter(loadStakeholderData({ includeArchived })),
          refreshAfter(loadPatientData({ includeArchived })),
          refreshAfter(loadSavedViews()),
          refreshAfter(refreshNotificationSummary())
        ]);
        updateView();
      }

      async function initializeData() {
        const initialRouteView = routeViewFromHash();
        let initialTargetView = initialRouteView || "home";
        try {
          await loadCriticalInitialData();
          scheduleDeferredInitialData();
        } catch (error) {
          console.error("Geschützte Anwendungsdaten konnten nicht über die API geladen werden.", error);
          if (teamDirectoryState === "loading") teamDirectoryState = "error";
          const message = String(error?.message || error?.details || "");
          const authFailed = /permission denied|JWT|auth|not authenticated|Unauthorized|401/i.test(message);
          if (window.dataService?.isConfigured?.() && authFailed && window.VKAuth) {
            window.VKAuth.clearAuthenticated();
            window.location.replace(window.VKAuth.buildLoginUrl());
            return;
          }
          contacts = [];
          organizations = [];
          loadedContactsFromStorage = false;
          setStorageStatus("Keine geschützten Kontaktdaten verfügbar");
          window.alert("Kontakte konnten nicht aus dem Backend geladen werden. Bitte prüfe Konfiguration, Anmeldung und Rollen.");
        }
        isInitialDataLoading = false;
        initialDataLoadingSlow = false;
        if (shouldRequireInitialOnboarding()) {
          if (transientInitialHomeSidebarCollapse) restoreSidebarState();
          await openOnboarding(initialTargetView || activeView || "home");
          finishInitialLoading();
          return;
        }
        if (initialTargetView) activeView = initialTargetView;
        setActiveView(activeView);
        updateView();
        finishInitialLoading();
      }

      function finishInitialLoading() {
        if (activeView === "home") resetHomeScrollPosition();
        appShell?.classList.remove("is-initializing");
        appShell?.removeAttribute("aria-busy");
        initialLoadingSkeleton?.setAttribute("aria-hidden", "true");
        if (activeView === "home") playHomeRevealHeading();
      }

      renderAccountProfile(null);
      window.setTimeout(() => {
        if (!isInitialDataLoading) return;
        initialDataLoadingSlow = true;
        updateView();
      }, 4200);
      initializeData();
